insert into public.recipes (slug, title, icon, category, time_label, description, region, state, data) values
  ('bife_parmegiana_light', 'Bife à Parmegiana Light', '🍖', 'Almoço · Paulistano', '40 min', 'Versão leve da parmegiana: bife grelhado, molho de tomate caseiro e queijo minas gratinado.', 'sudeste', 'SP', '{"ings":[{"n":"Filé mignon em bifes","a":"300 g"},{"n":"Molho de tomate caseiro","a":"1 xícara"},{"n":"Queijo minas fresco fatiado","a":"150 g"},{"n":"Orégano, alho, sal, pimenta","a":"a gosto"}],"steps":["Tempere os bifes com alho, sal e pimenta.","Grelhe em frigideira antiaderente por 2 min cada lado.","Transfira para refratário; cubra com molho de tomate.","Disponha queijo minas por cima e polvilhe orégano.","Gratine em forno a 200 °C por 10 min."],"tip":"Queijo minas no lugar da muçarela corta ~40% da gordura sem perder o efeito gratinado."}'::jsonb),
  ('canja_galinha_sudeste', 'Canja de Galinha', '🍲', 'Jantar · Reconfortante', '45 min', 'Caldo clássico de galinha com arroz e legumes — versão mineira simples.', 'sudeste', 'MG', '{"ings":[{"n":"Peito de galinha com osso","a":"300 g"},{"n":"Arroz cru","a":"1/3 xícara"},{"n":"Cenoura, batata, abobrinha em cubos","a":"2 xícaras"},{"n":"Cebola, alho, louro, salsinha","a":"a gosto"}],"steps":["Cozinhe a galinha em 1,5 l de água com louro por 30 min.","Retire, desfie e devolva o caldo ao fogo.","Adicione arroz e cozinhe por 8 min.","Junte os legumes; cozinhe mais 10 min.","Devolva a galinha desfiada; finalize com salsinha."],"tip":"Galinha caipira dá mais sabor mas exige 20 min a mais de cozimento."}'::jsonb),
  ('feijao_arroz_branco', 'Feijão Preto com Arroz Branco', '🍛', 'Almoço · Básico', '1h', 'O prato mais brasileiro: feijão preto temperado com arroz soltinho.', 'sudeste', 'RJ', '{"ings":[{"n":"Feijão preto","a":"1 xícara"},{"n":"Arroz branco cru","a":"1 xícara"},{"n":"Bacon ou linguiça (opcional)","a":"50 g"},{"n":"Cebola, alho, louro, cheiro-verde","a":"a gosto"}],"steps":["Deixe o feijão de molho por 4h; cozinhe em pressão com louro por 25 min.","Refogue alho e cebola em panela separada; junte o feijão.","Para o arroz: refogue alho/cebola, acrescente o arroz e água fervente (2:1).","Cozinhe o arroz tampado por 15 min em fogo baixo.","Finalize ambos com cheiro-verde."],"tip":"Bata 1 concha de feijão no liquidificador e devolva à panela — caldo fica cremoso."}'::jsonb),
  ('feijao_tropeiro', 'Feijão Tropeiro', '🌾', 'Almoço · Mineiro', '35 min', 'Feijão carioca misturado com farinha, ovo, bacon e linguiça — prato de viagem dos tropeiros.', 'sudeste', 'MG', '{"ings":[{"n":"Feijão carioca cozido escorrido","a":"2 xícaras"},{"n":"Farinha de mandioca","a":"1 xícara"},{"n":"Bacon em cubinhos","a":"100 g"},{"n":"Linguiça calabresa em rodelas","a":"100 g"},{"n":"Ovos, cebola, alho, cebolinha","a":"a gosto"}],"steps":["Frite o bacon até dourar; acrescente a linguiça.","Retire parte da gordura; refogue cebola e alho.","Bata os ovos, despeje na panela e mexa para formar pedacinhos.","Junte o feijão escorrido e misture bem.","Incorpore a farinha aos poucos mexendo sempre.","Finalize com cebolinha."],"tip":"Feijão escorrido SECO é o segredo — se tiver caldo, a farinha vira papa."}'::jsonb),
  ('lombo_feijao_preto_couve', 'Lombo Suíno Magro c/ Feijão Preto e Couve', '🍖', 'Almoço · Mineiro light', '25 min', 'Sabores da feijoada numa versão rápida e magra: lombo suíno grelhado, arroz, feijão preto e couve refogada.', 'sudeste', 'MG', '{"ings":[{"n":"Lombo suíno magro em filés","a":"130 g"},{"n":"Arroz branco cozido","a":"2 col sopa"},{"n":"Feijão preto cozido","a":"3 col sopa"},{"n":"Couve em tiras finas","a":"1 xícara"},{"n":"Laranja em fatias","a":"1/2 unidade"},{"n":"Alho, sal, pimenta, azeite","a":"a gosto"}],"steps":["Tempere o lombo com alho, sal e pimenta; 10 min.","Grelhe em frigideira quente 3-4 min cada lado.","Em paralelo, refogue alho; acrescente a couve; 2 min até murchar levemente.","Aqueça feijão preto e arroz.","Monte o prato: lombo fatiado, arroz, feijão, couve, fatias de laranja."],"tip":"Lombo magro tem 8g de gordura por 100g — vs 18g das carnes de feijoada tradicional."}'::jsonb),
  ('frango_quiabo_mineiro', 'Frango Ensopado Mineiro c/ Quiabo', '🐔', 'Almoço · Mineiro light', '25 min', 'Frango ensopado rápido com quiabo — sabores mineiros sem o tempo nem o sangue do molho pardo.', 'sudeste', 'MG', '{"ings":[{"n":"Peito de frango em cubos","a":"130 g"},{"n":"Quiabo em rodelas","a":"1 xícara"},{"n":"Angu de fubá (polenta mole)","a":"3 col sopa"},{"n":"Tomate, cebola, alho","a":"a gosto"},{"n":"Salada verde (acompanhamento)","a":"à vontade"},{"n":"Azeite, sal, pimenta, colorau","a":"a gosto"}],"steps":["Tempere o frango em cubos com alho, sal e colorau; 10 min.","Doure em fio de azeite; acrescente cebola e tomate picado.","Cubra com 1/2 xícara de água; cozinhe 8 min.","Adicione o quiabo em rodelas; cozinhe mais 5 min.","Em paralelo, prepare o angu: fubá em chuva no caldo quente, mexer 10 min.","Sirva o frango com angu e salada verde."],"tip":"Para o quiabo não ''babar'', lave em vinagre e seque antes de cortar em rodelas."}'::jsonb),
  ('lasanha_abobrinha_light', 'Lasanha de Abobrinha Light', '🥒', 'Jantar · Fit', '45 min', 'Lasanha sem massa — fatias finas de abobrinha, peito de frango e queijo minas.', 'sudeste', 'SP', '{"ings":[{"n":"Abobrinha em fatias finas","a":"2 grandes"},{"n":"Peito de frango desfiado cozido","a":"300 g"},{"n":"Molho de tomate","a":"1 xícara"},{"n":"Queijo minas fresco","a":"200 g"},{"n":"Manjericão, alho, azeite","a":"a gosto"}],"steps":["Grelhe as fatias de abobrinha por 1 min cada lado (tira água).","Refogue o frango desfiado com alho e molho de tomate.","Num refratário, alterne camadas: abobrinha, frango, queijo minas, repetir.","Termine com queijo minas por cima.","Asse a 200 °C por 20 min até gratinar.","Finalize com manjericão fresco."],"tip":"Grelhar a abobrinha antes tira o excesso de água — senão a lasanha fica aguada."}'::jsonb),
  ('macarronada_bolonhesa', 'Macarronada Integral à Bolonhesa', '🍝', 'Almoço · Ítalo-brasileiro', '35 min', 'Massa integral com molho de carne moída magra e tomate pelado.', 'sudeste', 'SP', '{"ings":[{"n":"Macarrão integral (penne ou espaguete)","a":"300 g"},{"n":"Carne moída magra","a":"300 g"},{"n":"Tomate pelado em lata","a":"1 lata"},{"n":"Cebola, alho, cenoura ralada, manjericão","a":"a gosto"}],"steps":["Doure cebola, alho e cenoura ralada em fio de azeite.","Acrescente a carne moída e refogue até secar.","Junte o tomate pelado amassado; cozinhe por 20 min.","Ajuste sal, pimenta e manjericão.","Cozinhe a massa al dente; escorra.","Sirva a massa com o molho generoso por cima."],"tip":"Cenoura ralada no molho adoça naturalmente — substitui o açúcar comum."}'::jsonb),
  ('moqueca_capixaba', 'Moqueca Capixaba', '🐟', 'Almoço · Capixaba', '35 min', 'Moqueca do ES — sem leite de coco, sem dendê, colorida com urucum e tomate.', 'sudeste', 'ES', '{"ings":[{"n":"Postas de peixe branco firme","a":"400 g"},{"n":"Tomate, cebola, pimentão em rodelas","a":"a gosto"},{"n":"Urucum em pó (colorau)","a":"1 col sopa"},{"n":"Azeite, limão, coentro, alho","a":"a gosto"}],"steps":["Tempere o peixe com limão, alho, urucum e sal; deixe 15 min.","Numa panela de barro, faça camadas: cebola, tomate, pimentão, peixe.","Regue com azeite e um pouco de água.","Cozinhe tampado em fogo baixo por 20 min sem mexer.","Finalize com muito coentro fresco."],"tip":"Diferença pra baiana: NÃO leva dendê nem leite de coco — a cor vem só do urucum."}'::jsonb),
  ('omelete_queijo_minas_sudeste', 'Omelete com Queijo Minas', '🍳', 'Jantar · Rápido', '10 min', 'Omelete simples com queijo minas fresco em cubos e cebolinha.', 'sudeste', 'MG', '{"ings":[{"n":"Ovos","a":"3 unidades"},{"n":"Queijo minas fresco em cubos","a":"80 g"},{"n":"Cebolinha, manteiga, sal, pimenta","a":"a gosto"}],"steps":["Bata os ovos com sal, pimenta e cebolinha.","Aqueça manteiga em frigideira antiaderente.","Despeje os ovos; quando firmar a base, adicione queijo.","Dobre ao meio e cozinhe mais 1 min.","Sirva com salada."],"tip":"Queijo minas fresco não derrete muito — cria bolsos de queijo macio no omelete."}'::jsonb),
  ('peito_frango_grelhado', 'Peito de Frango Grelhado', '🐔', 'Jantar · Fit', '20 min', 'Peito de frango grelhado simples com ervas — base de qualquer dieta.', 'sudeste', 'RJ', '{"ings":[{"n":"Peito de frango em filés","a":"300 g"},{"n":"Limão, alho, alecrim","a":"a gosto"},{"n":"Azeite, sal, pimenta","a":"a gosto"}],"steps":["Tempere com limão, alho amassado, alecrim, sal e pimenta; deixe 15 min.","Seque com papel-toalha antes de grelhar.","Aqueça frigideira com fio de azeite.","Grelhe 4 min cada lado em fogo médio-alto.","Deixe descansar 3 min antes de cortar."],"tip":"Bata o peito com tenderizer (ou fundo de panela) até ficar uniforme — grelha por igual."}'::jsonb),
  ('polenta_mole_frango_grelhado', 'Polenta Mole Leve c/ Frango Grelhado', '🌽', 'Almoço · Ítalo-brasileiro light', '22 min', 'Polenta mole sem queijo acompanhada de frango grelhado — combinação ítalo-brasileira mais leve, sem manteiga nem parmesão.', 'sudeste', 'SP', '{"ings":[{"n":"Fubá de milho fino","a":"1/3 xícara"},{"n":"Caldo de legumes","a":"1,5 xícaras"},{"n":"Peito de frango em filés","a":"120 g"},{"n":"Salada verde c/ tomate","a":"à vontade"},{"n":"Alho, sal, pimenta, azeite","a":"a gosto"}],"steps":["Tempere o frango com alho, sal, pimenta; 10 min.","Grelhe em fio de azeite por 4 min cada lado.","Em paralelo, ferva o caldo; despeje fubá em chuva mexendo.","Cozinhe a polenta 12 min em fogo baixo, mexendo ocasionalmente.","Não adicione queijo nem manteiga (versão leve).","Sirva o frango sobre a polenta + salada de folhas e tomate."],"tip":"Polenta sem queijo e manteiga fica mais leve — o frango grelhado entrega o sabor principal."}'::jsonb),
  ('polenta_mole_tomate', 'Polenta Mole ao Molho de Tomate', '🍅', 'Jantar · Leve', '30 min', 'Polenta cremosa com molho de tomate fresco e manjericão.', 'sudeste', 'MG', '{"ings":[{"n":"Fubá de milho fino","a":"1 xícara"},{"n":"Caldo de legumes","a":"4 xícaras"},{"n":"Tomates maduros picados","a":"3 unidades"},{"n":"Alho, manjericão, azeite","a":"a gosto"}],"steps":["Ferva o caldo; adicione o fubá em chuva mexendo.","Cozinhe em fogo baixo por 20 min.","Em paralelo, refogue alho em azeite; junte tomates picados.","Cozinhe o molho por 10 min.","Sirva a polenta com molho e manjericão."],"tip":"Use tomates bem maduros (preferencialmente italianos) — base doce e saborosa."}'::jsonb),
  ('quibe_assado', 'Quibe Assado', '🥖', 'Almoço · Árabe-paulistano', '1h', 'Quibe de trigo e carne moída assado no forno — versão paulistana tradicional.', 'sudeste', 'SP', '{"ings":[{"n":"Trigo para quibe (bulgur fino)","a":"1 xícara"},{"n":"Carne moída magra","a":"500 g"},{"n":"Cebola ralada","a":"1 unidade"},{"n":"Hortelã picada","a":"1/2 xícara"},{"n":"Sal, pimenta síria, azeite","a":"a gosto"}],"steps":["Hidrate o trigo em água fria por 30 min; escorra apertando bem.","Misture o trigo com a carne, cebola, hortelã, sal e pimenta síria.","Amasse até ficar homogêneo (como um patê).","Espalhe numa assadeira untada; faça losangos com a faca.","Regue com azeite e asse a 200 °C por 30 min.","Sirva com iogurte natural à parte."],"tip":"Pimenta síria muda o quibe — se não tiver, misture cominho + canela + cravo moídos."}'::jsonb),
  ('sopa_feijao_macarrao', 'Sopa de Feijão com Macarrão', '🥣', 'Jantar · Reconfortante', '40 min', 'Caldo de feijão com macarrão tipo letrinha ou conchinha.', 'sudeste', 'RJ', '{"ings":[{"n":"Feijão carioca cozido com caldo","a":"2 xícaras"},{"n":"Macarrão tipo conchinha ou ave-maria","a":"1/2 xícara"},{"n":"Cebola, alho, bacon (opcional)","a":"a gosto"},{"n":"Cheiro-verde, pimenta","a":"a gosto"}],"steps":["Bata metade do feijão com caldo no liquidificador.","Refogue cebola, alho e bacon em panela funda.","Junte o feijão batido e o inteiro + 500 ml de água morna.","Ferva; acrescente o macarrão e cozinhe por 8 min.","Finalize com cheiro-verde."],"tip":"Não deixe descansar — macarrão em sopa cresce e vira papa se esperar demais."}'::jsonb),
  ('sopa_legumes_frango', 'Sopa de Legumes com Frango', '🥣', 'Jantar · Leve', '35 min', 'Caldo leve com variedade de legumes e frango desfiado.', 'sudeste', 'MG', '{"ings":[{"n":"Peito de frango desfiado cozido","a":"200 g"},{"n":"Cenoura, chuchu, abobrinha, batata","a":"3 xícaras"},{"n":"Caldo de galinha","a":"1,5 l"},{"n":"Cebola, alho, cheiro-verde","a":"a gosto"}],"steps":["Cozinhe o frango em 1,5 l de água com cebola; desfie.","Corte todos os legumes em cubos pequenos.","Volte o caldo ao fogo; junte os legumes em ordem de firmeza.","Cozinhe até os legumes ficarem al dente (12 min).","Devolva o frango desfiado; ajuste sal.","Finalize com cheiro-verde."],"tip":"Legumes em cubos pequenos (~1cm) cozinham rápido e ficam bonitos na colher."}'::jsonb),
  ('frango_molho_tomate_brocolis', 'Frango ao Molho Rústico de Tomate c/ Brócolis', '🍗', 'Almoço · Fit', '20 min', 'Frango cozido em molho fresco de tomate com brócolis no vapor — alternativa ao strogonoff, sem creme de leite.', 'sudeste', 'SP', '{"ings":[{"n":"Peito de frango em tiras","a":"130 g"},{"n":"Tomates maduros picados","a":"2 unidades"},{"n":"Brócolis em floretes","a":"1 xícara"},{"n":"Arroz branco cozido","a":"2 col sopa"},{"n":"Salada verde","a":"à vontade"},{"n":"Cebola, alho, manjericão, azeite","a":"a gosto"}],"steps":["Tempere o frango com alho e sal; 10 min.","Refogue cebola em fio de azeite; acrescente frango em tiras.","Doure por 4 min; junte os tomates picados.","Cozinhe 8 min até formar molho rústico.","Em paralelo, cozinhe brócolis no vapor por 4 min (al dente).","Finalize com manjericão fresco.","Sirva com arroz e salada."],"tip":"Tomate maduro + manjericão fresco entregam cremosidade natural sem creme de leite."}'::jsonb),
  ('tilapia_grelhada', 'Tilápia Grelhada', '🐟', 'Jantar · Fit', '15 min', 'Filé de tilápia grelhado na manteiga com limão e alho.', 'sudeste', 'RJ', '{"ings":[{"n":"Filé de tilápia","a":"300 g"},{"n":"Limão, alho, manteiga","a":"a gosto"},{"n":"Sal, pimenta, salsinha","a":"a gosto"}],"steps":["Tempere os filés com limão, alho, sal e pimenta; 10 min.","Aqueça manteiga em frigideira antiaderente.","Grelhe 3 min cada lado em fogo médio-alto.","Finalize com salsinha e um extra de limão."],"tip":"Tilápia é um peixe delicado — não vire antes de formar crosta ou quebra."}'::jsonb),
  ('frango_desfiado_pure_abobora', 'Frango Desfiado c/ Purê de Abóbora', '🥧', 'Jantar · Fit', '20 min', 'Frango desfiado refogado com purê de abóbora leve — jantar fit sem massa de torta nem 30 min de forno.', 'sudeste', 'MG', '{"ings":[{"n":"Peito de frango desfiado cozido","a":"120 g"},{"n":"Abóbora cabotiá ou moranga","a":"200 g"},{"n":"Salada verde c/ tomate","a":"à vontade"},{"n":"Cebola, alho, azeite","a":"a gosto"},{"n":"Sal, pimenta, noz-moscada","a":"a gosto"}],"steps":["Cozinhe a abóbora em cubos por 12 min em água até amolecer.","Escorra e amasse com garfo; tempere com sal, pimenta e noz-moscada.","Refogue o frango desfiado com cebola e alho em fio de azeite.","Sirva o frango sobre o purê de abóbora.","Finalize com salada de folhas e tomate."],"tip":"Abóbora cabotiá é mais doce e cremosa — não precisa de manteiga para dar textura."}'::jsonb),
  ('vaca_atolada', 'Vaca Atolada', '🍖', 'Almoço · Mineiro', '2h', 'Costela bovina cozida com mandioca — a carne ''atola'' na mandioca amolecida.', 'sudeste', 'MG', '{"ings":[{"n":"Costela bovina em pedaços","a":"800 g"},{"n":"Mandioca descascada em pedaços","a":"600 g"},{"n":"Cebola, alho, tomate, colorau","a":"a gosto"},{"n":"Cheiro-verde, louro, pimenta","a":"a gosto"}],"steps":["Tempere a costela com alho, sal, pimenta e colorau; deixe 30 min.","Doure em panela de pressão com um fio de óleo.","Junte cebola, tomate e louro; cubra com água.","Cozinhe em pressão por 40 min.","Abra; adicione a mandioca em pedaços grandes.","Cozinhe sem pressão por 30 min até a mandioca desmanchar levemente.","Finalize com cheiro-verde."],"tip":"Mandioca tem que ''atolar'' — quer dizer desmanchar um pouco para engrossar o caldo."}'::jsonb),
  ('virado_paulista', 'Virado à Paulista', '🍛', 'Almoço · Paulistano', '45 min', 'Prato clássico paulista: feijão tropeiro + arroz + couve refogada + bisteca + ovo frito + banana.', 'sudeste', 'SP', '{"ings":[{"n":"Feijão tropeiro (ver outra receita)","a":"1 xícara"},{"n":"Arroz branco cozido","a":"1 xícara"},{"n":"Couve refogada em tiras","a":"1 xícara"},{"n":"Bisteca suína","a":"1 unidade"},{"n":"Ovo frito, banana frita","a":"1 cada"}],"steps":["Prepare o feijão tropeiro (ver receita separada).","Cozinhe arroz branco.","Refogue couve em tiras com alho e sal por 2 min (só aquecer).","Grelhe a bisteca temperada com alho e sal.","Frite a banana e o ovo em manteiga.","Monte o prato com todos os elementos lado a lado."],"tip":"Virado ''verdadeiro'' leva tutu de feijão (feijão batido com farinha) em vez do tropeiro seco."}'::jsonb),
  ('pao_de_queijo', 'Pão de Queijo Mineiro', '🧀', 'Café · Mineiro', '30 min', 'Pão de queijo clássico com polvilho azedo e queijo minas meia-cura — receita caseira simples.', 'sudeste', 'MG', '{"ings":[{"n":"Polvilho azedo","a":"500 g"},{"n":"Queijo minas meia-cura ralado","a":"200 g"},{"n":"Leite","a":"1 xícara"},{"n":"Óleo","a":"1/2 xícara"},{"n":"Ovos","a":"2 unidades"},{"n":"Sal","a":"1 col ch"}],"steps":["Ferva o leite com o óleo e o sal.","Escalde o polvilho com a mistura quente; misture bem.","Deixe amornar; acrescente os ovos e o queijo ralado.","Amasse até ficar liso e elástico.","Faça bolinhas de ~30g e disponha em assadeira untada.","Asse a 200 °C por 20 min até dourar."],"tip":"Para ficar crocante por fora e mole por dentro, asse com a assadeira já quente."}'::jsonb),
  ('quibe_assado_paulistano', 'Quibe Assado Paulistano (150g)', '🍞', 'Almoço · Árabe-paulistano', '1h', 'Versão maior do quibe assado tradicional de SP com porção reforçada.', 'sudeste', 'SP', '{"ings":[{"n":"Trigo para quibe","a":"1,5 xícaras"},{"n":"Carne moída magra","a":"700 g"},{"n":"Cebola ralada grande","a":"1 unidade"},{"n":"Hortelã picada","a":"3/4 xícara"},{"n":"Pimenta síria, sal, azeite","a":"a gosto"}],"steps":["Hidrate o trigo em água fria por 30 min; escorra apertando.","Misture todos os ingredientes até formar massa homogênea.","Espalhe em assadeira grande untada; corte em losangos.","Regue com azeite abundante.","Asse a 200 °C por 35 min até tostar as bordas.","Sirva com pão sírio e tahine."],"tip":"Pra ficar suculento, leve um copinho d''água no fundo do forno — cria vapor e não resseca."}'::jsonb),
  ('peixe_galo_grelhado_es', 'Peixe-Galo Grelhado Capixaba', '🐟', 'Almoço · Capixaba', '18 min', 'Peixe-galo grelhado ao limão com arroz e salada — peixe simbolo de Vitoria em versao leve.', 'sudeste', 'ES', '{"ings": [{"n": "Filé de peixe-galo (ou badejo)", "a": "130 g"}, {"n": "Arroz branco cozido", "a": "2 col sopa"}, {"n": "Folhas verdes c/ tomate", "a": "à vontade"}, {"n": "Limão, alho, coentro", "a": "a gosto"}, {"n": "Azeite, sal, pimenta-do-reino", "a": "a gosto"}], "steps": ["Tempere o peixe com limão, alho, sal e pimenta; 10 min.", "Seque a posta com papel-toalha.", "Grelhe em fio de azeite por 3 min cada lado sem mexer.", "Finalize com coentro picado.", "Sirva com arroz e salada verde."], "tip": "Peixe-galo tem carne branca firme — não mexa enquanto grelha, vira só 1 vez."}'::jsonb),
  ('muma_siri_light_es', 'Mumá de Siri Light', '🦀', 'Almoço · Capixaba', '25 min', 'Mumá capixaba de siri desfiado com urucum — versão leve sem azeite em excesso.', 'sudeste', 'ES', '{"ings": [{"n": "Carne de siri desfiada", "a": "150 g"}, {"n": "Tomate, cebola, pimentão picados", "a": "1 xícara"}, {"n": "Urucum (colorau)", "a": "1 col chá"}, {"n": "Arroz branco cozido", "a": "2 col sopa"}, {"n": "Coentro, alho, limão, azeite", "a": "a gosto"}], "steps": ["Refogue cebola, alho e pimentão em fio de azeite.", "Acrescente tomate e urucum; cozinhe 4 min.", "Junte o siri desfiado; cozinhe 6 min.", "Finalize com coentro e limão.", "Sirva com arroz."], "tip": "Urucum puro (sem mistura) é mais intenso — 1 col chá já dá a cor alaranjada da mumá."}'::jsonb),
  ('moqueca_camarao_capixaba', 'Moqueca de Camarão Capixaba', '🦐', 'Almoço · Capixaba', '22 min', 'Moqueca capixaba de camarão (sem dendê nem coco) em panela de barro — cor do urucum.', 'sudeste', 'ES', '{"ings": [{"n": "Camarões limpos", "a": "150 g"}, {"n": "Tomate, cebola, pimentão em rodelas", "a": "a gosto"}, {"n": "Urucum em pó", "a": "1 col chá"}, {"n": "Arroz branco cozido", "a": "2 col sopa"}, {"n": "Coentro, limão, alho, azeite", "a": "a gosto"}], "steps": ["Tempere o camarão com limão, alho, sal e urucum; 10 min.", "Numa panela, faça camadas: cebola, pimentão, tomate, camarão.", "Regue com fio de azeite e 1/2 xícara de água.", "Cozinhe tampado em fogo baixo 10 min.", "Finalize com coentro.", "Sirva com arroz."], "tip": "Camarão cozinha rápido — se passar de 10 min fica emborrachado."}'::jsonb),
  ('torta_capixaba_light', 'Torta Capixaba Light', '🥧', 'Almoço · Capixaba', '35 min', 'Torta com frutos do mar (siri, camarão, palmito) — versão fit usando claras em vez de gemas.', 'sudeste', 'ES', '{"ings": [{"n": "Carne de siri + camarão", "a": "150 g"}, {"n": "Palmito picado", "a": "1/2 xícara"}, {"n": "Claras batidas em neve", "a": "3 unidades"}, {"n": "Tomate, cebola, coentro", "a": "a gosto"}, {"n": "Urucum, azeite, sal", "a": "a gosto"}], "steps": ["Refogue cebola e alho; acrescente tomate e urucum.", "Junte siri, camarão e palmito; cozinhe 5 min.", "Ajuste sal e coentro; deixe esfriar um pouco.", "Bata claras em neve firme; misture delicadamente ao refogado.", "Despeje em refratário untado; asse a 180 °C por 20 min até dourar."], "tip": "Substituir gemas por claras em neve corta 70% da gordura mantendo a leveza."}'::jsonb),
  ('peixe_urucum_banana_es', 'Peixe Assado com Urucum e Banana-da-Terra', '🍌', 'Almoço · Capixaba', '25 min', 'Filé de peixe branco assado com urucum e banana-da-terra assada — sabor capixaba doce-salgado.', 'sudeste', 'ES', '{"ings": [{"n": "Filé de peixe branco", "a": "130 g"}, {"n": "Banana-da-terra madura em fatias", "a": "1 unidade"}, {"n": "Urucum em pó", "a": "1 col chá"}, {"n": "Folhas verdes", "a": "à vontade"}, {"n": "Limão, alho, azeite, sal", "a": "a gosto"}], "steps": ["Tempere o peixe com limão, alho, urucum, sal; 10 min.", "Disponha em assadeira; regue com fio de azeite.", "Distribua banana-da-terra em fatias ao redor.", "Asse a 200 °C por 18 min.", "Sirva com folhas verdes."], "tip": "Banana-da-terra madura (com manchas pretas) adoça naturalmente, dispensando açúcar."}'::jsonb),
  ('bobo_camarao_capixaba_light', 'Bobó de Camarão Capixaba Light', '🦐', 'Almoço · Capixaba', '30 min', 'Bobó de camarão com mandioca amassada e leite de coco light — versão fit da tradição capixaba.', 'sudeste', 'ES', '{"ings": [{"n": "Camarões limpos", "a": "150 g"}, {"n": "Mandioca cozida amassada", "a": "120 g"}, {"n": "Leite de coco light", "a": "1/4 xícara"}, {"n": "Tomate, cebola, pimentão", "a": "a gosto"}, {"n": "Coentro, urucum, alho, azeite", "a": "a gosto"}], "steps": ["Tempere o camarão com limão, alho, urucum; 10 min.", "Refogue cebola, alho, pimentão e tomate.", "Junte camarão e leite de coco light; cozinhe 5 min.", "Incorpore a mandioca amassada para engrossar.", "Cozinhe mais 5 min; finalize com coentro."], "tip": "Leite de coco light tem 40% menos gordura — fica cremoso sem pesar."}'::jsonb),
  ('caldo_peixe_capixaba', 'Caldo de Peixe Capixaba', '🥣', 'Jantar · Capixaba', '20 min', 'Caldo leve de peixe branco com batata e urucum — jantar reconfortante da orla de ES.', 'sudeste', 'ES', '{"ings": [{"n": "Filé de peixe branco em cubos", "a": "120 g"}, {"n": "Batata em cubos pequenos", "a": "100 g"}, {"n": "Tomate, cebola, pimentão", "a": "a gosto"}, {"n": "Caldo de legumes caseiro", "a": "800 ml"}, {"n": "Urucum, coentro, limão", "a": "a gosto"}], "steps": ["Ferva o caldo; acrescente batata em cubos; cozinhe 10 min.", "Junte tomate, cebola, pimentão e urucum.", "Acrescente o peixe em cubos; cozinhe 5 min.", "Ajuste sal e finalize com coentro e limão."], "tip": "Não cozinhe o peixe demais — 5 min é suficiente pra não desmanchar."}'::jsonb),
  ('moqueca_robalo_es', 'Moqueca de Robalo Capixaba', '🐟', 'Almoço · Capixaba', '25 min', 'Moqueca capixaba com robalo fresco — peixe nobre do litoral de ES.', 'sudeste', 'ES', '{"ings": [{"n": "Postas de robalo", "a": "150 g"}, {"n": "Tomate, cebola, pimentão em rodelas", "a": "a gosto"}, {"n": "Urucum em pó", "a": "1 col chá"}, {"n": "Arroz branco cozido", "a": "2 col sopa"}, {"n": "Coentro, alho, limão, azeite", "a": "a gosto"}], "steps": ["Tempere o robalo com limão, alho, urucum, sal; 15 min.", "Na panela (de preferência de barro), faça camadas: cebola, tomate, pimentão, peixe.", "Regue com fio de azeite e 1/2 xícara de água.", "Cozinhe tampado em fogo baixo por 15 min sem mexer.", "Finalize com muito coentro fresco.", "Sirva com arroz."], "tip": "Robalo é peixe delicado — panela de barro mantém temperatura e evita ressecar."}'::jsonb),
  ('pirao_capixaba_light', 'Pirão Capixaba Light c/ Peixe', '🍲', 'Almoço · Capixaba', '20 min', 'Pirão leve com caldo de peixe e farinha de mandioca — acompanha peixe grelhado.', 'sudeste', 'ES', '{"ings": [{"n": "Filé de peixe branco", "a": "130 g"}, {"n": "Farinha de mandioca fina", "a": "3 col sopa"}, {"n": "Caldo de peixe (ou legumes)", "a": "1,5 xícaras"}, {"n": "Cebola, alho, coentro, urucum", "a": "a gosto"}, {"n": "Azeite, sal, limão", "a": "a gosto"}], "steps": ["Tempere o peixe com limão, alho, sal; 10 min.", "Grelhe em fio de azeite 3 min cada lado; reserve.", "No caldo, refogue cebola, alho e urucum.", "Despeje a farinha em chuva mexendo sem parar; cozinhe 4 min.", "Sirva o peixe sobre o pirão; finalize com coentro."], "tip": "Pirão light leva pouca farinha — fica mais solto que o tradicional, com menos kcal."}'::jsonb),
  ('file_oswaldo_aranha_light', 'Filé Oswaldo Aranha Light', '🥩', 'Almoço · Carioca', '18 min', 'Filé mignon grelhado com chips de alho torrado — clássico carioca do Cosmopolita sem excesso de azeite.', 'sudeste', 'RJ', '{"ings": [{"n": "Filé mignon em medalhão", "a": "130 g"}, {"n": "Alho em lâminas", "a": "6 dentes"}, {"n": "Arroz branco cozido", "a": "2 col sopa"}, {"n": "Folhas verdes c/ tomate", "a": "à vontade"}, {"n": "Azeite, sal, pimenta-do-reino, limão", "a": "a gosto"}], "steps": ["Tempere o filé com sal e pimenta; deixe chegar à temperatura ambiente.", "Em fio de azeite, toste as lâminas de alho até dourar; reserve.", "Na mesma frigideira (bem quente), grelhe o filé 2 min cada lado.", "Deixe descansar 3 min antes de servir.", "Cubra o filé com os chips de alho dourado.", "Sirva com arroz e salada verde."], "tip": "Alho frito pela receita tradicional fica muito gorduroso — torrado em fio de azeite entrega a crocância sem o excesso."}'::jsonb),
  ('picadinho_carioca_light', 'Picadinho Carioca Light', '🥩', 'Almoço · Carioca', '22 min', 'Picadinho de filé mignon com ovo pochê — clássico carioca sem manteiga em excesso.', 'sudeste', 'RJ', '{"ings": [{"n": "Filé mignon em cubinhos", "a": "130 g"}, {"n": "Tomate, cebola picados", "a": "1 xícara"}, {"n": "Arroz branco cozido", "a": "2 col sopa"}, {"n": "Ovo para pochê", "a": "1 unidade"}, {"n": "Alho, cheiro-verde, azeite, sal", "a": "a gosto"}], "steps": ["Tempere o filé em cubinhos com alho e sal; 10 min.", "Doure em fio de azeite por 3 min.", "Acrescente cebola e tomate; cozinhe 6 min.", "Em paralelo, faça o ovo pochê (água fervente + vinagre por 3 min).", "Monte o prato: arroz + picadinho + ovo pochê por cima.", "Finalize com cheiro-verde."], "tip": "Ovo pochê substitui a manteiga do picadinho clássico — cremoso sem gordura saturada."}'::jsonb),
  ('bacalhau_assado_rj', 'Bacalhau Assado Carioca', '🐟', 'Almoço · Carioca', '25 min', 'Bacalhau dessalgado e assado com batata e cebola — clássico de festa em versão reduzida.', 'sudeste', 'RJ', '{"ings": [{"n": "Lombo de bacalhau dessalgado", "a": "130 g"}, {"n": "Batata cozida em fatias", "a": "100 g"}, {"n": "Cebola em rodelas", "a": "1 unidade"}, {"n": "Pimentão em tiras", "a": "1/2 unidade"}, {"n": "Azeitona preta, azeite, alho, salsinha", "a": "a gosto"}], "steps": ["Dessalgue o bacalhau por 24h trocando a água 3x.", "Em assadeira, faça camadas: batata, cebola, pimentão, bacalhau.", "Regue com fio de azeite e azeitonas.", "Asse a 200 °C por 20 min.", "Finalize com salsinha."], "tip": "Dessalgar bacalhau direito é o ponto principal — se não trocar a água, fica inedível."}'::jsonb),
  ('frango_xerem_rj', 'Frango ao Xerém Carioca', '🌽', 'Almoço · Carioca', '25 min', 'Frango grelhado sobre xerém (canjica amassada) temperado — herança da cozinha luso-carioca.', 'sudeste', 'RJ', '{"ings": [{"n": "Peito de frango grelhado em tiras", "a": "130 g"}, {"n": "Canjica branca cozida", "a": "1/2 xícara"}, {"n": "Caldo de legumes", "a": "1 xícara"}, {"n": "Cebola, alho, tomate", "a": "a gosto"}, {"n": "Cheiro-verde, azeite, sal", "a": "a gosto"}], "steps": ["Tempere o frango com alho, sal; 10 min; grelhe 4 min cada lado.", "Bata metade da canjica cozida com o caldo no liquidificador.", "Numa panela, refogue cebola e alho; acrescente tomate.", "Junte o xerém batido + canjica inteira; cozinhe 5 min mexendo.", "Sirva o frango sobre o xerém; finalize com cheiro-verde."], "tip": "Xerém é uma polenta ''''caroçuda'''' — metade batida, metade inteira, para ter textura."}'::jsonb),
  ('costela_mandioca_rj', 'Costela de Panela c/ Mandioca Carioca', '🥩', 'Almoço · Carioca', '30 min', 'Costela magra de panela com mandioca — prato clássico da mesa carioca em versão enxuta.', 'sudeste', 'RJ', '{"ings": [{"n": "Costela magra em pedaços", "a": "130 g"}, {"n": "Mandioca cozida em cubos", "a": "120 g"}, {"n": "Cebola, alho, tomate, louro", "a": "a gosto"}, {"n": "Folhas verdes", "a": "à vontade"}, {"n": "Cheiro-verde, azeite, sal, colorau", "a": "a gosto"}], "steps": ["Tempere a costela com alho, sal, colorau; 15 min.", "Doure em pressão com fio de azeite por 3 min.", "Acrescente cebola, tomate e louro; cubra com água.", "Cozinhe em pressão 25 min.", "Sirva sobre mandioca em cubos com folhas verdes.", "Finalize com cheiro-verde."], "tip": "Costela magra (sem ripa) tem metade da gordura — ainda mantém o sabor de osso."}'::jsonb),
  ('feijoada_light_rj', 'Feijoada Carioca Light', '🫘', 'Almoço · Carioca', '30 min', 'Feijoada adaptada: feijão preto + lombo magro + carne seca desfiada (sem paio, sem linguiça) — sabor sem o excesso de gordura.', 'sudeste', 'RJ', '{"ings": [{"n": "Feijão preto cozido com caldo", "a": "1 xícara"}, {"n": "Lombo suíno magro em cubos", "a": "80 g"}, {"n": "Carne seca desfiada dessalgada", "a": "50 g"}, {"n": "Arroz branco cozido", "a": "2 col sopa"}, {"n": "Couve em tiras, laranja em fatias", "a": "a gosto"}, {"n": "Alho, louro, cebola, azeite", "a": "a gosto"}], "steps": ["Tempere o lombo com alho e sal; doure em fio de azeite.", "Junte carne seca desfiada; refogue 3 min.", "Acrescente feijão cozido com caldo e louro.", "Cozinhe 10 min em fogo baixo para pegar sabor.", "Em paralelo, refogue alho; murche a couve por 2 min.", "Monte: arroz + feijoada light + couve + laranja."], "tip": "Cortar paio, linguiça calabresa e bacon reduz 60% da gordura saturada mantendo o espírito da feijoada."}'::jsonb),
  ('nhoque_mandioquinha_sp', 'Nhoque de Mandioquinha c/ Frango', '🥔', 'Almoço · Paulistano', '30 min', 'Nhoque leve de mandioquinha (batata-baroa) com ragu de frango desfiado — alternativa sem batata branca e sem manteiga.', 'sudeste', 'SP', '{"ings": [{"n": "Mandioquinha cozida e amassada", "a": "150 g"}, {"n": "Farinha de trigo", "a": "1/3 xícara"}, {"n": "Ovo", "a": "1 unidade"}, {"n": "Peito de frango desfiado cozido", "a": "100 g"}, {"n": "Tomate pelado, cebola, alho, manjericão", "a": "a gosto"}], "steps": ["Amasse a mandioquinha quente; misture com ovo, farinha e pitada de sal.", "Forme um cilindro; corte em pedacinhos de 2cm.", "Cozinhe em água fervente salgada; retire quando subirem (~2 min).", "Em paralelo, refogue cebola, alho; acrescente frango desfiado e tomate pelado.", "Cozinhe o ragu por 8 min.", "Sirva o nhoque com o ragu; finalize com manjericão."], "tip": "Mandioquinha tem amido suficiente para ligar sem 3 xícaras de farinha — fica mais leve."}'::jsonb),
  ('yakisoba_light_sp', 'Yakisoba Paulistano Light', '🥢', 'Almoço · Paulistano', '20 min', 'Yakisoba da Liberdade adaptado: frango magro, muitos legumes, shoyu light — versão fit do clássico asiático de SP.', 'sudeste', 'SP', '{"ings": [{"n": "Peito de frango em tiras", "a": "120 g"}, {"n": "Macarrão para yakisoba integral", "a": "80 g"}, {"n": "Brócolis, cenoura, repolho, pimentão", "a": "2 xícaras"}, {"n": "Shoyu light, gengibre ralado, alho", "a": "a gosto"}, {"n": "Azeite, cebolinha, semente de gergelim", "a": "a gosto"}], "steps": ["Cozinhe o macarrão al dente; escorra e reserve.", "Tempere o frango com shoyu light e gengibre; 10 min.", "Aqueça fio de azeite em wok ou frigideira grande; saltear frango 3 min.", "Acrescente legumes em ordem de firmeza (cenoura, brócolis, pimentão, repolho); 4 min.", "Junte o macarrão e 2 col sopa de shoyu light; misture.", "Finalize com cebolinha e gergelim."], "tip": "Shoyu light corta 50% do sódio — para uma refeição diária, a diferença é importante."}'::jsonb)
