-- Migration 0026: seed de receitas Sudeste (gerado por scripts/generate-recipes-seed.mjs)
-- 40 receitas curadas para region='sudeste' (10 por estado: ES, MG, RJ, SP). UPSERT por slug.

delete from public.recipes where region = 'sudeste';

on conflict (slug) do update set
  title = excluded.title,
  icon = excluded.icon,
  category = excluded.category,
  time_label = excluded.time_label,
  description = excluded.description,
  region = excluded.region,
  state = excluded.state,
  data = excluded.data;
